const Table = (props) => {


    const products = props.data.products;


    return (
        <div>
            <li>
                {products.map((product) => (
                    <ul>{product.number} {product.name} {product.price.gender}</ul>
                ))}
            </li>
        </div>
    );
}

export default Table;
